# tests/test_sanitizer.py
import pytest
from security.sanitizer import sanitize_html


class TestBasicSanitization:
    """Basic tests for the sanitizer - expand these significantly."""

    def test_plain_text_passes_through(self):
        assert sanitize_html("Hello world") == "Hello world"

    def test_strips_script_tags(self):
        result = sanitize_html('<script>alert("xss")</script>')
        assert '<script' not in result.lower()
        assert 'alert' not in result.lower()

    def test_allows_bold(self):
        assert '<b>' in sanitize_html('<b>bold text</b>')

    def test_allows_italic(self):
        assert '<i>' in sanitize_html('<i>italic text</i>')
